/**
 * Pricer for CDS tranche trade based on ISDA standard model.
 * <p>
 * The underlying CDS tranche product is priced using the index-based pricer with tranche-specific adjustments.
 */
public class IsdaCdsTrancheTradePricer {

  /**
   * Default implementation.
   */
  public static final IsdaCdsTrancheTradePricer DEFAULT = new IsdaCdsTrancheTradePricer();

  /**
   * The product pricer.
   */
  private final IsdaCdsTrancheProductPricer productPricer;
  /**
   * The upfront fee pricer.
   */
  private final DiscountingPaymentPricer upfrontPricer;

  //-------------------------------------------------------------------------
  /**
   * The default constructor.
   * <p>
   * The default pricers are used.
   */
  public IsdaCdsTrancheTradePricer() {
    this.productPricer = IsdaCdsTrancheProductPricer.DEFAULT;
    this.upfrontPricer = DiscountingPaymentPricer.DEFAULT;
  }

  /**
   * The constructor with the accrual-on-default formula specified.
   *
   * @param formula  the accrual-on-default formula
   */
  public IsdaCdsTrancheTradePricer(AccrualOnDefaultFormula formula) {
    this.productPricer = new IsdaCdsTrancheProductPricer(formula);
    this.upfrontPricer = DiscountingPaymentPricer.DEFAULT;
  }

  //-------------------------------------------------------------------------
  /**
   * Gets the accrual-on-default formula used in this pricer.
   *
   * @return the formula
   */
  public AccrualOnDefaultFormula getAccrualOnDefaultFormula() {
    return productPricer.getAccrualOnDefaultFormula();
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value of the CDS tranche trade.
   * <p>
   * The present value of the product is based on {@code referenceDate}.
   * This is typically the valuation date, or cash settlement date if the product is associated with a {@code Trade}.
   * <p>
   * This method can calculate the clean or dirty present value, see {@link PriceType}.
   * If calculating the clean value, the accrued interest is calculated based on the step-in date.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the present value
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      PriceType priceType,
      ReferenceData refData) {

    LocalDate settlementDate = calculateSettlementDate(trade, ratesProvider, refData);
    CurrencyAmount pv = productPricer.presentValue(
        trade.getProduct(), ratesProvider, settlementDate, priceType, refData);
    if (trade.getUpfrontFee().isPresent()) {
      CurrencyAmount upfrontPv = upfrontPricer.presentValue(trade.getUpfrontFee().get(), ratesProvider);
      pv = pv.plus(upfrontPv);
    }
    return pv;
  }

  /**
   * Calculates the present value sensitivity of the CDS tranche trade.
   * <p>
   * The present value sensitivity of the trade is the sensitivity of present value to the underlying curves.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param refData  the reference data
   * @return the present value sensitivity
   */
  public PointSensitivities presentValueSensitivity(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    LocalDate settlementDate = calculateSettlementDate(trade, ratesProvider, refData);
    PointSensitivityBuilder pvSensi = productPricer.presentValueSensitivity(
        trade.getProduct(), ratesProvider, settlementDate, refData);
    return pvSensi.build();
  }

  //-------------------------------------------------------------------------
  // helper method to calculate settlement date
  private LocalDate calculateSettlementDate(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    return trade.getProduct().getUnderlyingIndex().getSettlementDateOffset()
        .adjust(ratesProvider.getValuationDate(), refData);
  }

}

